// Formato ContaSol - CSV con separador ;
const facturas = $('Leer Facturas PostgreSQL').all().map(i => i.json);
const body = $('Webhook').first().json.body || {};
const ejercicio = body.ejercicio || new Date().getFullYear().toString();

// ContaSol: Asiento;Fecha;Cuenta;Debe;Haber;Concepto;Documento;NIF
const lineas = ['Asiento;Fecha;Cuenta;Debe;Haber;Concepto;Documento;NIF'];
let numAsiento = 1;

for (const f of facturas) {
  const fecha = f.fecha_factura || '';
  const esCompra = (f.tipo_documento || 'compra') !== 'venta';
  const base = Number(f.base_imponible) || Number(f.total_factura) || 0;
  const iva = Number(f.cuota_iva) || 0;
  const total = Number(f.total_factura) || 0;
  const cuenta = f.cuenta_gasto || '629';
  const concepto = (f.nombre_emisor || '').replace(/;/g, ',');
  const nif = f.nif_emisor || '';
  const doc = (f.numero_factura || '').replace(/;/g, ',');
  const as = String(numAsiento);

  if (esCompra) {
    lineas.push(as + ';' + fecha + ';' + cuenta + ';' + base.toFixed(2) + ';0.00;' + concepto + ';' + doc + ';' + nif);
    if (iva > 0) lineas.push(as + ';' + fecha + ';472;' + iva.toFixed(2) + ';0.00;IVA ' + concepto + ';' + doc + ';' + nif);
    lineas.push(as + ';' + fecha + ';400;0.00;' + total.toFixed(2) + ';' + concepto + ';' + doc + ';' + nif);
  } else {
    lineas.push(as + ';' + fecha + ';430;' + total.toFixed(2) + ';0.00;' + concepto + ';' + doc + ';' + nif);
    lineas.push(as + ';' + fecha + ';' + (cuenta || '705') + ';0.00;' + base.toFixed(2) + ';' + concepto + ';' + doc + ';' + nif);
    if (iva > 0) lineas.push(as + ';' + fecha + ';477;0.00;' + iva.toFixed(2) + ';IVA ' + concepto + ';' + doc + ';' + nif);
  }
  numAsiento++;
}

return [{
  json: {
    success: true,
    total_facturas: facturas.length,
    formato: 'ContaSol',
    csv_content: lineas.join('\n'),
    filename: 'kontia_contasol_' + new Date().toISOString().split('T')[0] + '.csv'
  }
}];
